    var ADDS = [{"p":"PART 6. 납세담보의 평가·변경·납부·징수·해제","q":[{"answer":"O","text":"납세담보로 제공한 금전으로 지방자치단체의 징수금을 납부하려는 자는 그 뜻을 적은 문서로 지방자치단체의 장에게 신청하여야 하고, 이 경우 신청한 금액에 상당하는 지방자치단체의 징수금을 납부한 것으로 본다.","exp":"담보로 맡긴 금전은 곧바로 징수금 납부에 충당할 수 있고, 문서로 신청하면 신청한 금액에 상당하는 징수금을 납부한 것으로 본다. 이미 지방자치단체가 보관 중인 금전이므로 별도 승인 없이 납부 효력이 생긴다.","src":"2024 서울시 7급"},{"answer":"X","text":"납세담보로 제공한 금전으로 지방자치단체의 징수금을 납부하려는 자가 그 뜻을 적은 문서로 신청하더라도, 지방자치단체의 장의 승인이 있기 전까지는 신청한 금액에 상당하는 징수금을 납부한 것으로 보지 아니한다.","exp":"'승인 전까지 납부한 것으로 보지 아니한다'가 틀렸다. 담보 금전에 의한 납부는 신청한 금액에 상당하는 징수금을 납부한 것으로 본다. 이미 지자체가 보관 중인 금전이라 별도 승인 절차 없이 납부 효력이 발생한다."}],"tb":[{"k":"p","t":"납세담보로 금전을 제공한 자는 그 금전으로 담보한 지방자치단체의 징수금을 납부할 수 있다. 그 뜻을 문서로 신청하면 신청한 금액에 상당하는 징수금을 납부한 것으로 본다(이미 지자체가 보관 중인 금전이라 별도 승인 없이 충당된다). 금전·실물 유가증권은 공탁, 등록채권은 등록으로 '제공'하는 것과, 이렇게 제공된 금전으로 '납부'하는 것을 구별한다."}],"wi":["📝 \"담보 금전으로 징수금 납부를 신청해도 지자체장의 승인 전까지는 납부한 것으로 보지 않는다\" → ❌ 신청한 금액 상당액을 납부한 것으로 본다(별도 승인 불요)."]}];
